                    <InputNumber class="form-control" @bind-Value="NewProduct!.Quantity" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Unit Price</label>
                    <InputNumber class="form-control" @bind-Value="NewProduct!.UnitPrice" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Category</label>
                    <InputSelect class="form-select" @bind-Value="NewProduct!.Category">
                        <option value="">-- Select --</option>
                        <option value="Electronics">Electronics</option>
                        <option value="Clothing">Clothing</option>
                        <option value="Food">Food</option>
                        <option value="Other">Other</option>
                    </InputSelect>
                </div>
                <div class="col-md-2">
                    <button type="submit" class="btn btn-primary w-100">Add</button>
                </div>
            </div>
        </EditForm>
    </div>
</div>

@* Product table *@
<table class="table table-striped">
    <thead>
        <tr>
            <th>Name</th>
            <th>Quantity</th>
            <th>Unit Price</th>
            <th>Category</th>
            <th>Actions</th>
        </tr>
    </thead>
    <tbody>
        @if (products is not null)
        {
            @foreach (var product in products)
            {
                @if (editingProductId == product.Id)
                {
                    <EditRow Product="product"
                             OnSave="HandleSave"
                             OnCancel="HandleCancel"
                             @rendermode="InteractiveServer" />
                }
                else
                {
                    <tr>
                        <td>@product.Name</td>
                        <td>@product.Quantity</td>
                        <td>@product.UnitPrice.ToString("C")</td>
                        <td>@product.Category</td>
                        <td>
                            <form method="post" @formname="@($"edit-{product.Id}")" @onsubmit="() => StartEdit(product.Id)">
                                <AntiforgeryToken />
                                <input type="hidden" name="productId" value="@product.Id" />
                                <button type="submit" class="btn btn-sm btn-outline-secondary">Edit</button>
                            </form>
                        </td>
                    </tr>
                }
            }
        }
    </tbody>
</table>

@code {
    private List<Product>? products;
    private int? editingProductId;

    [SupplyParameterFromForm(FormName = "QuickAdd")]
    private Product? NewProduct { get; set; }

    [SupplyParameterFromForm(FormName = "StartEdit")]
    private int? EditProductId { get; set; }

    protected override void OnInitialized()
    {
        NewProduct ??= new();
    }

    protected override async Task OnInitializedAsync()
    {
        products = await InventoryService.GetAllAsync();
        CheckEditFormSubmissions();
    }

    private void CheckEditFormSubmissions()
    {
        // Check if any edit-{id} form was submitted by looking at EditProductId
        // This is handled via the individual form submissions below
    }

    private void StartEdit(int productId)
    {
        editingProductId = productId;
    }

    private async Task HandleAdd()
    {
        if (NewProduct is not null)
        {
            await InventoryService.AddAsync(NewProduct);
            Nav.Refresh(forceReload: true);
        }
    }

    private async Task HandleSave(Product product)
    {
        await InventoryService.UpdateAsync(product);
        editingProductId = null;
        products = await InventoryService.GetAllAsync();
    }

    private void HandleCancel()
    {
        editingProductId = null;
    }
}
"}

